    pub fn parse_trade(&mut self, mut trade: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        //
        // fetchTrades
        //
        //        {
        //            "symbol": "BTC_USDT_PERP",
        //            "revisionId": "1130514101",
        //            "size": "0.01668",
        //            "price": "116309.57",
        //            "takerSide": "sell",
        //            "time": "1753439710374047"
        //        }
        //
        // fetchMyTrades
        //
        //        {
        //            "symbol": "SOL_USDT",
        //            "revisionId": "891839406",
        //            "size": "0.042",
        //            "price": "185.06",
        //            "takerSide": "sell",
        //            "time": "1753773952039342",
        //            "orderId": "3717304929194",
        //            "userSide": "sell",
        //            "quoteFee": "0.00777252",
        //            "arkmFee": "0",
        //            "clientOrderId": ""
        //        }
        //
        let mut marketId: Value = self.safe_string_k(trade.clone(), "symbol", &[]);
        market = self.safe_market(&[marketId.clone(), market.clone()]);
        let mut timestamp: Value = self.safe_integer_product(trade.clone(), Value::Str("time".to_string()), Value::Float(0.001), &[]);
        let mut quoteFee: Value = self.safe_number_k(trade.clone(), "quoteFee", &[]);
        let mut arkmFee: Value = self.safe_number_k(trade.clone(), "arkmFee", &[]);
        let mut fee: Value = Value::Null;
        if !is_equal(&quoteFee, &Value::Null) {
            fee = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("cost".to_string(), quoteFee.clone());
                    m.insert("currency".to_string(), get_value(&market, &Value::Str("quote".to_string())));
                m
            });
        }  else if !is_equal(&arkmFee, &Value::Null) {
            fee = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("cost".to_string(), arkmFee.clone());
                    m.insert("currency".to_string(), Value::Str("ARKM".to_string()));
                m
            });
        }
        return self.safe_trade(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), trade.clone());
        m.insert("id".to_string(), self.safe_string_k(trade.clone(), "revisionId", &[]));
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("symbol".to_string(), get_value(&market, &Value::Str("symbol".to_string())));
        m.insert("type".to_string(), Value::Null);
        m.insert("side".to_string(), self.safe_string2(trade.clone(), Value::Str("userSide".to_string()), Value::Str("takerSide".to_string()), &[]));
        m.insert("takerOrMaker".to_string(), Value::Null);
        m.insert("price".to_string(), self.safe_string_k(trade.clone(), "price", &[]));
        m.insert("amount".to_string(), self.safe_string_k(trade.clone(), "size", &[]));
        m.insert("cost".to_string(), Value::Null);
        m.insert("fee".to_string(), fee.clone());
        m.insert("order".to_string(), self.safe_string_k(trade.clone(), "orderId", &[]));
    m
}), &[market.clone()]);

    Value::Null
}

