        let mut isMarketOrder: Value = Value::Bool(is_equal(&type_var, &Value::Str("market".to_string())));
        let mut isLimitOrder: Value = Value::Bool(is_equal(&type_var, &Value::Str("limit".to_string())));
        let mut isLimitExchangeSpecific: Value = self.in_array(type_var.clone(), Value::List(vec![Value::Str("limitGtc".to_string()), Value::Str("limitIoc".to_string()), Value::Str("limitFok".to_string())]));
